   259→void ConnectionManagerImpl::doEndStream(ActiveStream& stream, bool check_for_deferred_close) {
   260→  // The order of what happens in this routine is important and a little complicated. We first see
   261→  // if the stream needs to be reset. If it needs to be, this will end up invoking reset callbacks
   262→  // and then moving the stream to the deferred destruction list. If the stream has not been reset,
   263→  // we move it to the deferred deletion list here. Then, we potentially close the connection. This
   264→  // must be done after deleting the stream since the stream refers to the connection and must be
   265→  // deleted first.
   266→  bool reset_stream = false;
   267→  // If the response encoder is still associated with the stream, reset the stream. The exception
   268→  // here is when Envoy "ends" the stream by calling recreateStream at which point recreateStream
   269→  // explicitly nulls out response_encoder to avoid the downstream being notified of the
   270→  // Envoy-internal stream instance being ended.
   271→  if (stream.response_encoder_ != nullptr &&
   272→      (!stream.filter_manager_.hasLastDownstreamByteReceived() ||
   273→       !stream.state_.codec_saw_local_complete_)) {
   274→    // Indicate local is complete at this point so that if we reset during a continuation, we don't
   275→    // raise further data or trailers.
   276→    ENVOY_STREAM_LOG(debug, "doEndStream() resetting stream", stream);
   277→    // TODO(snowp): This call might not be necessary, try to clean up + remove setter function.
   278→    stream.filter_manager_.setLocalComplete();
   279→    stream.state_.codec_saw_local_complete_ = true;
   280→
   281→    // Per https://tools.ietf.org/html/rfc7540#section-8.3 if there was an error
   282→    // with the TCP connection during a CONNECT request, it should be
   283→    // communicated via CONNECT_ERROR
   284→    if (requestWasConnect(stream.request_headers_, codec_->protocol()) &&
   285→        (stream.filter_manager_.streamInfo().hasResponseFlag(
   286→             StreamInfo::CoreResponseFlag::UpstreamConnectionFailure) ||
   287→         stream.filter_manager_.streamInfo().hasResponseFlag(
   288→             StreamInfo::CoreResponseFlag::UpstreamConnectionTermination))) {
   289→      stream.response_encoder_->getStream().resetStream(StreamResetReason::ConnectError);
   290→    } else {
   291→      const bool reset_with_error =
   292→          Runtime::runtimeFeatureEnabled("envoy.reloadable_features.reset_with_error");
   293→      if (stream.filter_manager_.streamInfo().hasResponseFlag(
   294→              StreamInfo::CoreResponseFlag::UpstreamProtocolError) &&
   295→          !Runtime::runtimeFeatureEnabled(
   296→              "envoy.reloadable_features.reset_ignore_upstream_reason")) {
   297→        stream.response_encoder_->getStream().resetStream(StreamResetReason::ProtocolError);
   298→      } else if (reset_with_error && stream.filter_manager_.streamInfo().hasResponseFlag(
   299→                                         StreamInfo::CoreResponseFlag::DownstreamProtocolError)) {
   300→        stream.response_encoder_->getStream().resetStream(StreamResetReason::ProtocolError);
   301→      } else {
   302→        stream.response_encoder_->getStream().resetStream(StreamResetReason::LocalReset);
   303→      }
   304→    }
   305→    reset_stream = true;
   306→  }
   307→
   308→  if (!reset_stream) {
   309→    doDeferredStreamDestroy(stream);
   310→  }
   311→
   312→  if (reset_stream && codec_->protocol() < Protocol::Http2) {
   313→    drain_state_ = DrainState::Closing;
   314→  }
   315→
   316→  if (check_for_deferred_close) {
   317→    checkForDeferredClose(stream.shouldSkipDeferredCloseDelay());
   318→  }
   319→}
